endmodule

module HEAD_CONTROLLER(

    input clk,
    input reset_b,
    input RAM_Overflow,
    input data_ready,

    output reg Head_Counter_sel


);

    parameter [1:0]     
        START_UP = 2'b00,
        INCREMENT = 2'b01,
        HOLDANDWAIT = 2'b10,
        HOLD = 2'b11;

    reg [1:0] current_state, next_state;

    always@(posedge clk or negedge reset_b) begin
        if(!reset_b) begin
            current_state = START_UP;
        end
        else begin
            current_state = next_state;
        end
    end

    always@(*) begin

        case(current_state) 
            START_UP:begin
                Head_Counter_sel <= 1'b1;
                if(RAM_Overflow) next_state <= INCREMENT;
                else next_state <= START_UP;
            end
            INCREMENT: begin
                Head_Counter_sel <= 1'b0;
                next_state <= HOLDANDWAIT;
            end
            HOLDANDWAIT: begin
                Head_Counter_sel <= 1'b1;
                if(data_ready) next_state <= HOLDANDWAIT;
                else next_state <= HOLD; 
            end
            HOLD: begin
                Head_Counter_sel <= 1'b1;
                if(data_ready) next_state <= INCREMENT;
                else next_state <= HOLD;
            end 
        endcase

    end


endmodule


module WRITE_CONTROLLER(

    input clk,
    input reset_b,
    input data_ready,

    output reg RAM_Write_Address_sel    

);

    reg[1:0] current_state, next_state;

    parameter[1:0]
        HOLD = 2'b00,
        INCREMENTANDWRITE = 2'b01,
        HOLDANDWAIT = 2'b10;

    always@(posedge clk or negedge reset_b) begin
        if(!reset_b) begin
            current_state <= HOLD;
        end    
        else begin
            current_state <= next_state;
        end
    end    

    always@(*) begin

        case(current_state)
            HOLD: begin
                RAM_Write_Address_sel = 1'b1;
                if(data_ready) next_state <= INCREMENTANDWRITE;
                else next_state <= HOLD;
            end
            INCREMENTANDWRITE: begin
                RAM_Write_Address_sel = 1'b0;
                next_state <= HOLDANDWAIT;
            end
            HOLDANDWAIT: begin
                RAM_Write_Address_sel = 1'b1;
                if(!data_ready) next_state <= HOLD;
                else next_state <= HOLDANDWAIT;
            end
            default: begin
                RAM_Write_Address_sel = 1'b0;
                next_state <= HOLD;
            end            
        endcase

    end 

endmodule



module READ_CONTROLLER(

    input clk,
    input reset_b,
    input Send_Frame,

    output reg RAM_Read_Address_sel

);

    reg current_state, next_state;

    parameter 
        HEAD = 1'b0,
        INCREMENT = 1'b1;

    always@(posedge clk or negedge reset_b) begin
        if(!reset_b) begin
            current_state <= HEAD;
        end
        else begin
            current_state <= next_state;
        end
    end

    always@(*) begin
        case(current_state)
            HEAD:begin
                RAM_Read_Address_sel <= 1'b1;
                if(Send_Frame) next_state = INCREMENT;
                else next_state = HEAD;
            end 
            INCREMENT:begin
                RAM_Read_Address_sel <= 1'b0;
                if(!Send_Frame) next_state = HEAD;
                else next_state = INCREMENT;
            end
        endcase
    end


endmodule

